    def __enter__(self):
        for lock in self.locks:
            lock.__enter__()

    def __exit__(self, *args):
        for lock in self.locks:
            lock.__exit__(*args)

    def locked(self):
        return any(lock.locked() for lock in self.locks)

    def __repr__(self):
        return f"CombinedLock({list(self.locks)!r})"

